import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useToast } from '../context/ToastContext';
import { ShieldAlert, UserPlus, Fingerprint, Mail, Lock } from 'lucide-react';

const RegisterPage = () => {
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const { register } = useAuth();
  const toast = useToast();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    const tid = toast.loading('INITIALIZING_IDENTITY...');
    try {
      await register(formData);
      toast.success('IDENTITY_CREATED', { id: tid });
      navigate('/login');
    } catch (err) {
      toast.error('REGISTRATION_FAILED', { id: tid });
    }
  };

  return (
    <div className="vault-card reveal-node">
      <div className="animate-laser" />
      
      <div className="flex flex-col items-center mb-8">
        <div className="p-4 bg-emerald-500/10 rounded-2xl mb-4">
          <UserPlus className="text-[var(--accent-primary)]" size={32} />
        </div>
        <h2 className="text-2xl font-light tracking-[0.3em] uppercase">Initialize_Node</h2>
        <p className="text-[10px] text-[var(--text-muted)] tracking-widest mt-2">SYSTEM_ACCESS_REQUISITION</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-5">
        <div className="flex flex-col gap-2">
          <label className="text-[10px] font-bold text-[var(--accent-primary)] uppercase tracking-widest flex items-center gap-2">
            <Fingerprint size={12} /> Operator_Name
          </label>
          <input 
            type="text" className="cyber-input" placeholder="Full Name"
            onChange={(e) => setFormData({...formData, name: e.target.value})} required
          />
        </div>

        <div className="flex flex-col gap-2">
          <label className="text-[10px] font-bold text-[var(--accent-primary)] uppercase tracking-widest flex items-center gap-2">
            <Mail size={12} /> Registry_Email
          </label>
          <input 
            type="email" className="cyber-input" placeholder="operator@finify.ai"
            onChange={(e) => setFormData({...formData, email: e.target.value})} required
          />
        </div>

        <div className="flex flex-col gap-2">
          <label className="text-[10px] font-bold text-[var(--accent-primary)] uppercase tracking-widest flex items-center gap-2">
            <Lock size={12} /> Security_Key
          </label>
          <input 
            type="password" className="cyber-input" placeholder="••••••••"
            onChange={(e) => setFormData({...formData, password: e.target.value})} required
          />
        </div>

        <button type="submit" className="cyber-btn mt-4">
          <ShieldAlert size={16} /> Execute_Onboarding
        </button>
      </form>

      <div className="mt-8 pt-6 border-t border-[var(--surface-border)] text-center">
        <Link to="/login" className="text-[10px] text-[var(--accent-primary)] font-bold uppercase tracking-widest hover:underline">
          Return_to_Access_Gate
        </Link>
      </div>
    </div>
  );
};

export default RegisterPage;
